 19→/// The active view in the application.
 20→pub enum View {
 21→    CheckpointList,
 22→    /// Checkpoint detail — carries the checkpoint index into `cache.checkpoints()`.
 23→    CheckpointDetail(usize),
 24→    /// Fullscreen transcript — checkpoint index + session index.
 25→    Transcript {
 26→        checkpoint_idx: usize,
 27→        session_idx: usize,
 28→    },
 29→    /// Diff view — commit hash.
