123→    pub fn run_git(dir: &Path, args: &[&str]) {
124→        let output = Command::new("git")
125→            .args(["-c", "protocol.file.allow=always"])
126→            .args(args)
127→            .current_dir(dir)
128→            .output()
129→            .expect("git command failed to start");
130→        assert!(
131→            output.status.success(),
132→            "git {} failed in {}: {}",
133→            args.join(" "),
134→            dir.display(),
135→            String::from_utf8_lossy(&output.stderr),
136→        );
137→    }
