139→    pub fn assert_paths_eq(actual: &Path, expected: &Path) {
140→        let actual = std::fs::canonicalize(actual)
141→            .unwrap_or_else(|_| panic!("cannot canonicalize {}", actual.display()));
142→        let expected = std::fs::canonicalize(expected)
143→            .unwrap_or_else(|_| panic!("cannot canonicalize {}", expected.display()));
144→        assert_eq!(actual, expected);
145→    }
